import{_ as e,c as t,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"AI App Factory 빠르게 시작: 설치부터 첫 번째 앱 실행까지 | agent-app-factory","description":"AI App Factory를 빠르게 시작하는 방법을 배우세요. CLI 도구 설치 및 구성부터 7단계 파이프라인 이해까지 첫 번째 앱을 생성하는 방법을 다룹니다.","frontmatter":{"title":"AI App Factory 빠르게 시작: 설치부터 첫 번째 앱 실행까지 | agent-app-factory","sidebarTitle":"시작하기","subtitle":"시작하기","description":"AI App Factory를 빠르게 시작하는 방법을 배우세요. CLI 도구 설치 및 구성부터 7단계 파이프라인 이해까지 첫 번째 앱을 생성하는 방법을 다룹니다.","order":10},"headers":[],"relativePath":"ko/hyz1992/agent-app-factory/start/index.md","filePath":"ko/hyz1992/agent-app-factory/start/index.md"}'),l={name:"ko/hyz1992/agent-app-factory/start/index.md"};function o(n,a,p,s,d,c){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="시작하기" tabindex="-1">시작하기 <a class="header-anchor" href="#시작하기" aria-label="Permalink to &quot;시작하기&quot;">​</a></h1><p>이 장에서는 AI App Factory를 빠르게 시작할 수 있도록 핵심 가치를 이해하고, 도구를 설치 및 구성하며, 7단계 파이프라인의 작동 원리를 파악하여 첫 번째 앱을 생성할 준비를 합니다.</p><h2 id="학습-경로" tabindex="-1">학습 경로 <a class="header-anchor" href="#학습-경로" aria-label="Permalink to &quot;학습 경로&quot;">​</a></h2><p>이 장의 내용을 다음 순서대로 학습하는 것을 권장합니다:</p><h3 id="_1-빠른-시작-아이디어부터-앱까지" tabindex="-1">1. <a href="./../getting-started/">빠른 시작: 아이디어부터 앱까지</a> <a class="header-anchor" href="#_1-빠른-시작-아이디어부터-앱까지" aria-label="Permalink to &quot;1. [빠른 시작: 아이디어부터 앱까지](../getting-started/)&quot;">​</a></h3><p>AI App Factory의 핵심 가치와 전제 요구사항을 이해하고, 전체 사례를 통해 아이디어부터 앱까지의 엔드투엔드 프로세스를 경험해 보세요.</p><ul><li>체크포인트 기반의 다중 에이전트 협업 메커니즘 이해</li><li>7단계 파이프라인의 전체 작업 흐름 파악</li><li>명확한 제품 설명을 제공하는 기술 습득</li></ul><h3 id="_2-설치-및-구성" tabindex="-1">2. <a href="./../installation/">설치 및 구성</a> <a class="header-anchor" href="#_2-설치-및-구성" aria-label="Permalink to &quot;2. [설치 및 구성](../installation/)&quot;">​</a></h3><p>CLI 도구를 전역 설치하고, AI 도우미(Claude Code/OpenCode) 및 관련 환경을 구성하세요.</p><ul><li>npm을 사용하여 agent-app-factory 전역 설치</li><li>Claude Code 또는 OpenCode 구성</li><li>설치 성공 여부 확인</li></ul><h3 id="_3-factory-프로젝트-초기화" tabindex="-1">3. <a href="./../init-project/">Factory 프로젝트 초기화</a> <a class="header-anchor" href="#_3-factory-프로젝트-초기화" aria-label="Permalink to &quot;3. [Factory 프로젝트 초기화](../init-project/)&quot;">​</a></h3><p><code>factory init</code> 명령을 사용하여 디렉터리를 초기화하고, 생성된 프로젝트 구조와 구성 파일을 이해하세요.</p><ul><li>프로젝트 초기화 명령 실행</li><li>프로젝트 디렉터리 구조와 구성 파일 이해</li><li>제품 아이디어 입력 준비</li></ul><h3 id="_4-7단계-파이프라인-개요" tabindex="-1">4. <a href="./../pipeline-overview/">7단계 파이프라인 개요</a> <a class="header-anchor" href="#_4-7단계-파이프라인-개요" aria-label="Permalink to &quot;4. [7단계 파이프라인 개요](../pipeline-overview/)&quot;">​</a></h3><p>Bootstrap부터 Preview까지 전체 파이프라인 프로세스, 각 단계의 입력/출력 및 체크포인트 메커니즘을 심층적으로 이해하세요.</p><ul><li>7단계의 목표와 산출물 이해</li><li>체크포인트 메커니즘 및 수동 확인 프로세스 마스터</li><li>파이프라인 실행 제어 방법 학습</li></ul><h2 id="전제-조건" tabindex="-1">전제 조건 <a class="header-anchor" href="#전제-조건" aria-label="Permalink to &quot;전제 조건&quot;">​</a></h2><p>이 장을 학습하기 전에 다음이 필요합니다:</p><div class="warning custom-block"><p class="custom-block-title">전제 요구사항</p><ol><li><strong>Node.js 환경</strong>: Node.js v18 이상이 설치되어 있어야 합니다.</li><li><strong>AI 프로그래밍 도우미</strong>: 다음 도구 중 하나를 구성해야 합니다. <ul><li><a href="https://claude.ai/code" target="_blank" rel="noreferrer">Claude Code</a> (추천) ⭐</li><li><a href="https://opencode.design/" target="_blank" rel="noreferrer">OpenCode</a> 또는 에이전트 모드를 지원하는 다른 AI 도우미</li></ul></li><li><strong>기본 명령줄 작업</strong>: 터미널에서 명령을 실행할 수 있어야 합니다.</li></ol></div><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>이 장의 학습을 완료하면 다음을 마스터하게 됩니다:</p><ul><li>✅ AI App Factory의 핵심 작동 원리</li><li>✅ CLI 도구의 설치 및 구성</li><li>✅ 프로젝트 초기화 및 구조 이해</li><li>✅ 7단계 파이프라인의 전체 프로세스</li></ul><p>다음으로 <strong><a href="./../../platforms/">플랫폼 및 통합</a></strong> 장을 학습하여 다양한 AI 도우미에서 파이프라인을 실행하는 방법을 알아보세요.</p>',23)])])}const f=e(l,[["render",o]]);export{u as __pageData,f as default};
